import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AssetType {
  STOCK = 'Stock',
  ETF = 'ETF',
  COMMODITY = 'Commodity',
  CRYPTO = 'Crypto',
  CASH = 'Cash'
}

export interface Asset {
  id: string;
  symbol: string;
  name: string;
  type: AssetType;
  quantity: number;
  avgPrice: number;
  currentPrice: number; // In a real app, this would be fetched live
  currency: string;
}

export interface PortfolioStats {
  totalValue: number;
  totalCost: number;
  totalGainLoss: number;
  totalGainLossPercentage: number;
}

export interface AIAnalysisResult {
  riskScore: number;
  riskAssessment: string;
  suggestions: string[];
  diversificationStatus: string;
}

// Global declaration for the SheetJS library loaded via CDN
declare global {
  interface Window {
    XLSX: any;
  }
}

import { GoogleGenAI, Type } from "@google/genai";
import { Asset, AIAnalysisResult } from "../types";

const API_KEY = process.env.API_KEY || '';

export const analyzePortfolio = async (assets: Asset[]): Promise<AIAnalysisResult> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Simplify the asset list for the prompt to save tokens
  const portfolioSummary = assets.map(a => ({
    symbol: a.symbol,
    type: a.type,
    value: (a.quantity * a.currentPrice).toFixed(2),
    allocation: ((a.quantity * a.currentPrice) / assets.reduce((sum, item) => sum + (item.quantity * item.currentPrice), 0) * 100).toFixed(1) + '%'
  }));

  const prompt = `
    Analyze the following investment portfolio summary. 
    Provide a risk score (1-10, where 10 is high risk), a brief risk assessment, 3 specific suggestions for improvement, and a comment on diversification.

    Portfolio Data:
    ${JSON.stringify(portfolioSummary, null, 2)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            riskScore: { type: Type.NUMBER, description: "Risk score from 1 to 10" },
            riskAssessment: { type: Type.STRING, description: "Short assessment of the risk level" },
            suggestions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "List of 3 actionable suggestions"
            },
            diversificationStatus: { type: Type.STRING, description: "Comment on how diversified the portfolio is" }
          },
          required: ["riskScore", "riskAssessment", "suggestions", "diversificationStatus"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIAnalysisResult;

  } catch (error) {
    console.error("Error analyzing portfolio:", error);
    // Return a fallback in case of error to prevent UI crash
    return {
      riskScore: 0,
      riskAssessment: "Could not analyze portfolio at this time.",
      suggestions: ["Ensure API Key is valid", "Check internet connection", "Try again later"],
      diversificationStatus: "Unknown"
    };
  }
};

import { Asset, AssetType } from "../types";

export const exportPortfolioToExcel = (assets: Asset[]) => {
  if (!window.XLSX) {
    alert("Excel library not loaded. Please refresh the page.");
    return;
  }

  // Prepare data for export (flattening if necessary, though our structure is flat)
  const data = assets.map(asset => ({
    Symbol: asset.symbol,
    Name: asset.name,
    Type: asset.type,
    Quantity: asset.quantity,
    "Avg Price": asset.avgPrice,
    "Current Price": asset.currentPrice,
    Currency: asset.currency,
    "Total Value": asset.quantity * asset.currentPrice
  }));

  const worksheet = window.XLSX.utils.json_to_sheet(data);
  const workbook = window.XLSX.utils.book_new();
  window.XLSX.utils.book_append_sheet(workbook, worksheet, "Portfolio");

  // Generate filename with date
  const date = new Date().toISOString().split('T')[0];
  window.XLSX.writeFile(workbook, `WealthFolio_Export_${date}.xlsx`);
};

export const parseExcelImport = (file: File): Promise<Asset[]> => {
  return new Promise((resolve, reject) => {
    if (!window.XLSX) {
      reject("Excel library not loaded.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = window.XLSX.read(data, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = window.XLSX.utils.sheet_to_json(worksheet);

        // Map generic JSON back to our Asset interface
        // Note: Needs robust error checking in prod, assuming happy path for demo
        const parsedAssets: Asset[] = json.map((row: any, index: number) => ({
          id: `imported-${Date.now()}-${index}`,
          symbol: row.Symbol || row.symbol || 'UNK',
          name: row.Name || row.name || 'Unknown Asset',
          type: (row.Type || row.type || AssetType.STOCK) as AssetType,
          quantity: Number(row.Quantity || row.quantity || 0),
          avgPrice: Number(row['Avg Price'] || row.avgPrice || 0),
          currentPrice: Number(row['Current Price'] || row.currentPrice || 0),
          currency: row.Currency || row.currency || 'USD'
        }));

        resolve(parsedAssets);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = (err) => reject(err);
    reader.readAsBinaryString(file);
  });
};

import React from 'react';
import { Asset } from '../types';

interface AssetTableProps {
  assets: Asset[];
  onDelete: (id: string) => void;
}

export const AssetTable: React.FC<AssetTableProps> = ({ assets, onDelete }) => {
  if (assets.length === 0) {
    return (
      <div className="text-center py-12 bg-white rounded-lg shadow-sm border border-slate-200">
        <p className="text-slate-500">No assets found. Add an investment or import an Excel sheet.</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto bg-white rounded-lg shadow-sm border border-slate-200">
      <table className="w-full text-left text-sm text-slate-600">
        <thead className="bg-slate-50 text-xs uppercase text-slate-500 font-semibold">
          <tr>
            <th className="px-6 py-4">Symbol</th>
            <th className="px-6 py-4">Name</th>
            <th className="px-6 py-4">Type</th>
            <th className="px-6 py-4 text-right">Quantity</th>
            <th className="px-6 py-4 text-right">Avg Cost</th>
            <th className="px-6 py-4 text-right">Current</th>
            <th className="px-6 py-4 text-right">Value</th>
            <th className="px-6 py-4 text-right">Gain/Loss</th>
            <th className="px-6 py-4 text-center">Actions</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {assets.map((asset) => {
            const totalValue = asset.quantity * asset.currentPrice;
            const totalCost = asset.quantity * asset.avgPrice;
            const gainLoss = totalValue - totalCost;
            const gainLossPercent = totalCost > 0 ? (gainLoss / totalCost) * 100 : 0;
            const isProfitable = gainLoss >= 0;

            return (
              <tr key={asset.id} className="hover:bg-slate-50 transition-colors">
                <td className="px-6 py-4 font-medium text-slate-900">{asset.symbol}</td>
                <td className="px-6 py-4">{asset.name}</td>
                <td className="px-6 py-4">
                  <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
                    ${asset.type === 'Stock' ? 'bg-blue-100 text-blue-800' : 
                      asset.type === 'ETF' ? 'bg-purple-100 text-purple-800' : 
                      asset.type === 'Commodity' ? 'bg-amber-100 text-amber-800' : 
                      'bg-slate-100 text-slate-800'}`}>
                    {asset.type}
                  </span>
                </td>
                <td className="px-6 py-4 text-right">{asset.quantity.toLocaleString()}</td>
                <td className="px-6 py-4 text-right">${asset.avgPrice.toFixed(2)}</td>
                <td className="px-6 py-4 text-right">${asset.currentPrice.toFixed(2)}</td>
                <td className="px-6 py-4 text-right font-semibold text-slate-900">${totalValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</td>
                <td className={`px-6 py-4 text-right ${isProfitable ? 'text-emerald-600' : 'text-rose-600'}`}>
                  <div className="flex flex-col items-end">
                    <span>{isProfitable ? '+' : ''}{gainLoss.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                    <span className="text-xs opacity-75">({isProfitable ? '+' : ''}{gainLossPercent.toFixed(2)}%)</span>
                  </div>
                </td>
                <td className="px-6 py-4 text-center">
                  <button 
                    onClick={() => onDelete(asset.id)}
                    className="text-slate-400 hover:text-rose-500 transition-colors p-1"
                    title="Delete Asset"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
};

import React from 'react';
import { PortfolioStats } from '../types';

