import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Asset } from '../types';

interface ChartsProps {
  assets: Asset[];
}

const COLORS = ['#3b82f6', '#8b5cf6', '#f59e0b', '#10b981', '#ef4444', '#6366f1'];

export const Charts: React.FC<ChartsProps> = ({ assets }) => {
  // Aggregate data for Pie Chart (Allocation by Type)
  const allocationData = React.useMemo(() => {
    const map = new Map<string, number>();
    assets.forEach(asset => {
      const val = asset.quantity * asset.currentPrice;
      map.set(asset.type, (map.get(asset.type) || 0) + val);
    });
    return Array.from(map.entries()).map(([name, value]) => ({ name, value }));
  }, [assets]);

  // Top 5 Assets by Value for Bar Chart
  const topAssetsData = React.useMemo(() => {
    return [...assets]
      .sort((a, b) => (b.quantity * b.currentPrice) - (a.quantity * a.currentPrice))
      .slice(0, 5)
      .map(a => ({
        name: a.symbol,
        value: a.quantity * a.currentPrice
      }));
  }, [assets]);

  if (assets.length === 0) return null;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-80">
        <h3 className="text-slate-800 font-semibold mb-4">Asset Allocation</h3>
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <Pie
              data={allocationData}
              cx="50%"
              cy="50%"
              innerRadius={60}
              outerRadius={80}
              paddingAngle={5}
              dataKey="value"
            >
              {allocationData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
              ))}
            </Pie>
            <Tooltip 
              formatter={(value: number) => `$${value.toLocaleString(undefined, {minimumFractionDigits: 0, maximumFractionDigits: 0})}`} 
              contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
            />
            <Legend verticalAlign="bottom" height={36}/>
          </PieChart>
        </ResponsiveContainer>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 h-80">
        <h3 className="text-slate-800 font-semibold mb-4">Top 5 Holdings by Value</h3>
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={topAssetsData} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
             <CartesianGrid strokeDasharray="3 3" horizontal={false} />
            <XAxis type="number" hide />
            <YAxis type="category" dataKey="name" width={50} tick={{fontSize: 12}} />
            <Tooltip 
               formatter={(value: number) => `$${value.toLocaleString()}`}
               cursor={{fill: 'transparent'}}
               contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
            />
            <Bar dataKey="value" fill="#3b82f6" radius={[0, 4, 4, 0]} barSize={20} />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useRef } from 'react';
import { Asset, AssetType, PortfolioStats, AIAnalysisResult } from './types';
import { AssetTable } from './components/AssetTable';
import { DashboardStats } from './components/DashboardStats';
import { Charts } from './components/Charts';
import { AssetForm } from './components/AssetForm';
import { analyzePortfolio } from './services/geminiService';
import { exportPortfolioToExcel, parseExcelImport } from './services/excelService';

// Initial Mock Data
const MOCK_ASSETS: Asset[] = [
  { id: '1', symbol: 'AAPL', name: 'Apple Inc.', type: AssetType.STOCK, quantity: 50, avgPrice: 150, currentPrice: 175.50, currency: 'USD' },
  { id: '2', symbol: 'VOO', name: 'Vanguard S&P 500 ETF', type: AssetType.ETF, quantity: 20, avgPrice: 350, currentPrice: 410.20, currency: 'USD' },
  { id: '3', symbol: 'GLD', name: 'SPDR Gold Shares', type: AssetType.COMMODITY, quantity: 10, avgPrice: 180, currentPrice: 192.30, currency: 'USD' },
  { id: '4', symbol: 'MSFT', name: 'Microsoft Corp', type: AssetType.STOCK, quantity: 30, avgPrice: 280, currentPrice: 320.10, currency: 'USD' },
];

const App: React.FC = () => {
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [aiResult, setAiResult] = useState<AIAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Derived Statistics
  const stats: PortfolioStats = useMemo(() => {
    const totalValue = assets.reduce((sum, asset) => sum + (asset.quantity * asset.currentPrice), 0);
    const totalCost = assets.reduce((sum, asset) => sum + (asset.quantity * asset.avgPrice), 0);
    const totalGainLoss = totalValue - totalCost;
    const totalGainLossPercentage = totalCost > 0 ? (totalGainLoss / totalCost) * 100 : 0;
    return { totalValue, totalCost, totalGainLoss, totalGainLossPercentage };
  }, [assets]);

  const handleAddAsset = (asset: Asset) => {
    setAssets([...assets, asset]);
  };

  const handleDeleteAsset = (id: string) => {
    setAssets(assets.filter(a => a.id !== id));
  };

  const handleExport = () => {
    exportPortfolioToExcel(assets);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        const importedAssets = await parseExcelImport(file);
        // confirm before replacing or merge? For simplicity, we merge/append
        if (window.confirm(`Found ${importedAssets.length} assets. Add them to your portfolio?`)) {
          setAssets(prev => [...prev, ...importedAssets]);
        }
      } catch (error) {
        console.error("Import failed", error);
        alert("Failed to import Excel file. Please ensure columns are: Symbol, Name, Type, Quantity, Avg Price, Current Price.");
      }
    }
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAIAnalysis = async () => {
    if (assets.length === 0) return;
    setIsAnalyzing(true);
    setAiResult(null);
    try {
      const result = await analyzePortfolio(assets);
      setAiResult(result);
    } catch (error) {
      console.error(error);
      alert("AI Analysis failed. Check console or API Key.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Navigation */}
      <nav className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-blue-200">W</div>
              <h1 className="text-xl font-bold text-slate-800 tracking-tight">WealthFolio</h1>
            </div>
            <div className="flex items-center gap-3">
               <button 
                onClick={handleAIAnalysis}
                className="hidden sm:flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-violet-600 to-indigo-600 text-white rounded-lg hover:shadow-lg hover:shadow-indigo-200 transition-all font-medium text-sm"
                disabled={isAnalyzing}
              >
                {isAnalyzing ? (
                   <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                     <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                     <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                   </svg>
                ) : (
                  <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                  </svg>
                )}
                AI Insights
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {/* AI Results Section */}
        {aiResult && (
          <div className="mb-8 animate-fade-in-down">
            <div className="bg-gradient-to-br from-indigo-50 to-violet-50 rounded-xl p-6 border border-indigo-100 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <svg className="w-32 h-32 text-indigo-600" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 17h-2v-2h2v2zm2.07-7.75l-.9.92C13.45 12.9 13 13.5 13 15h-2v-.5c0-1.1.45-2.1 1.17-2.83l1.24-1.26c.37-.36.59-.86.59-1.41 0-1.1-.9-2-2-2s-2 .9-2 2H8c0-2.21 1.79-4 4-4s4 1.79 4 4c0 .88-.36 1.68-.93 2.25z"/></svg>
              </div>
              <div className="relative z-10">
                <div className="flex items-center justify-between mb-4">
                  <h2 className="text-xl font-bold text-indigo-900">Portfolio Analysis</h2>
                  <button onClick={() => setAiResult(null)} className="text-indigo-400 hover:text-indigo-600">
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                  </button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className="bg-white/60 p-4 rounded-lg backdrop-blur-sm">
                    <p className="text-xs font-semibold text-indigo-500 uppercase tracking-wide">Risk Score</p>
                    <div className="flex items-end gap-2">
                       <span className={`text-4xl font-bold ${aiResult.riskScore > 7 ? 'text-rose-500' : aiResult.riskScore > 4 ? 'text-amber-500' : 'text-emerald-500'}`}>{aiResult.riskScore}</span>
                       <span className="text-indigo-900 pb-1">/ 10</span>
                    </div>
                    <p className="text-sm text-slate-600 mt-2">{aiResult.riskAssessment}</p>
                  </div>
                  <div className="bg-white/60 p-4 rounded-lg backdrop-blur-sm md:col-span-2">
                    <p className="text-xs font-semibold text-indigo-500 uppercase tracking-wide mb-2">Suggestions</p>
                    <ul className="space-y-2">
                      {aiResult.suggestions.map((s, i) => (
                        <li key={i} className="flex gap-2 text-sm text-slate-700">
                          <svg className="w-5 h-5 text-indigo-500 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                          {s}
                        </li>
                      ))}
                    </ul>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Overview Stats */}
        <DashboardStats stats={stats} />

        {/* Visualization */}
        <Charts assets={assets} />

        {/* Toolbar & Asset Table */}
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
          <h2 className="text-xl font-bold text-slate-800">Your Assets</h2>
          <div className="flex gap-2 w-full sm:w-auto">
            {/* Hidden File Input */}
            <input 
              type="file" 
              accept=".xlsx, .xls" 
              ref={fileInputRef} 
              className="hidden" 
              onChange={handleFileChange}
            />

            <button 
