import React, { useState, useMemo, useRef } from 'react';
import { Asset, AssetType, PortfolioStats, AIAnalysisResult } from './types';
import { AssetTable } from './components/AssetTable';
import { DashboardStats } from './components/DashboardStats';
import { Charts } from './components/Charts';
import { AssetForm } from './components/AssetForm';
import { analyzePortfolio } from './services/geminiService';
import { exportPortfolioToExcel, parseExcelImport } from './services/excelService';

// Initial Mock Data
const MOCK_ASSETS: Asset[] = [
  { id: '1', symbol: 'AAPL', name: 'Apple Inc.', type: AssetType.STOCK, quantity: 50, avgPrice: 150, currentPrice: 175.50, currency: 'USD' },
  { id: '2', symbol: 'VOO', name: 'Vanguard S&P 500 ETF', type: AssetType.ETF, quantity: 20, avgPrice: 350, currentPrice: 410.20, currency: 'USD' },
  { id: '3', symbol: 'GLD', name: 'SPDR Gold Shares', type: AssetType.COMMODITY, quantity: 10, avgPrice: 180, currentPrice: 192.30, currency: 'USD' },
  { id: '4', symbol: 'MSFT', name: 'Microsoft Corp', type: AssetType.STOCK, quantity: 30, avgPrice: 280, currentPrice: 320.10, currency: 'USD' },
];

const App: React.FC = () => {
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [aiResult, setAiResult] = useState<AIAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [darkMode, setDarkMode] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Derived Statistics
  const stats: PortfolioStats = useMemo(() => {
    const totalValue = assets.reduce((sum, asset) => sum + (asset.quantity * asset.currentPrice), 0);
    const totalCost = assets.reduce((sum, asset) => sum + (asset.quantity * asset.avgPrice), 0);
    const totalGainLoss = totalValue - totalCost;
    const totalGainLossPercentage = totalCost > 0 ? (totalGainLoss / totalCost) * 100 : 0;
    return { totalValue, totalCost, totalGainLoss, totalGainLossPercentage };
  }, [assets]);

  const handleAddAsset = (asset: Asset) => {
    setAssets([...assets, asset]);
  };

  const handleDeleteAsset = (id: string) => {
    setAssets(assets.filter(a => a.id !== id));
  };

  const handleExport = () => {
    exportPortfolioToExcel(assets);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        const importedAssets = await parseExcelImport(file);
        // confirm before replacing or merge? For simplicity, we merge/append
        if (window.confirm(`Found ${importedAssets.length} assets. Add them to your portfolio?`)) {
          setAssets(prev => [...prev, ...importedAssets]);
        }
      } catch (error) {
        console.error("Import failed", error);
        alert("Failed to import Excel file. Please ensure columns are: Symbol, Name, Type, Quantity, Avg Price, Current Price.");
      }
    }
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleAIAnalysis = async () => {
    if (assets.length === 0) return;
    setIsAnalyzing(true);
    setAiResult(null);
    try {
      const result = await analyzePortfolio(assets);
      setAiResult(result);
    } catch (error) {
      console.error(error);
      alert("AI Analysis failed. Check console or API Key.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className={darkMode ? "dark" : ""}>
      <div className="min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 pb-20 transition-colors duration-200">
        {/* Navigation */}
        <nav className="sticky top-0 z-30 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 transition-colors">
