                <div className="absolute top-0 right-0 p-4 opacity-10">
                  <svg className="w-32 h-32 text-indigo-600 dark:text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 17h-2v-2h2v2zm2.07-7.75l-.9.92C13.45 12.9 13 13.5 13 15h-2v-.5c0-1.1.45-2.1 1.17-2.83l1.24-1.26c.37-.36.59-.86.59-1.41 0-1.1-.9-2-2-2s-2 .9-2 2H8c0-2.21 1.79-4 4-4s4 1.79 4 4c0 .88-.36 1.68-.93 2.25z"/></svg>
                </div>
                <div className="relative z-10">
                  <div className="flex items-center justify-between mb-4">
                    <h2 className="text-xl font-bold text-indigo-900 dark:text-indigo-100">Portfolio Analysis</h2>
                    <button onClick={() => setAiResult(null)} className="text-indigo-400 hover:text-indigo-600 dark:text-indigo-300 dark:hover:text-indigo-100">
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                    </button>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="bg-white/60 dark:bg-slate-800/60 p-4 rounded-lg backdrop-blur-sm transition-colors">
                      <p className="text-xs font-semibold text-indigo-500 dark:text-indigo-300 uppercase tracking-wide">Risk Score</p>
                      <div className="flex items-end gap-2">
                         <span className={`text-4xl font-bold ${aiResult.riskScore > 7 ? 'text-rose-500' : aiResult.riskScore > 4 ? 'text-amber-500' : 'text-emerald-500'}`}>{aiResult.riskScore}</span>
                         <span className="text-indigo-900 dark:text-indigo-100 pb-1">/ 10</span>
                      </div>
                      <p className="text-sm text-slate-600 dark:text-slate-300 mt-2">{aiResult.riskAssessment}</p>
                    </div>
                    <div className="bg-white/60 dark:bg-slate-800/60 p-4 rounded-lg backdrop-blur-sm md:col-span-2 transition-colors">
