                  <div className="relative w-10 h-10 bg-slate-900 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-xl border border-slate-800">
                    <span className="bg-clip-text text-transparent bg-gradient-to-tr from-blue-400 to-cyan-300">W</span>
                  </div>
                </div>
                <h1 className="text-2xl font-bold text-slate-800 dark:text-slate-100 tracking-tight">
                  Wealth<span className="text-blue-600 dark:text-cyan-400">Folio</span>
                </h1>
              </div>
              <div className="flex items-center gap-4">
                 <button
