                      ${asset.type === 'Stock' ? 'bg-blue-100 text-blue-700 dark:bg-blue-500/10 dark:text-blue-400' : 
                        asset.type === 'ETF' ? 'bg-violet-100 text-violet-700 dark:bg-violet-500/10 dark:text-violet-400' : 
                        asset.type === 'Commodity' ? 'bg-amber-100 text-amber-700 dark:bg-amber-500/10 dark:text-amber-400' : 
                        'bg-slate-100 text-slate-700 dark:bg-slate-700/30 dark:text-slate-400'}`}>
                      {asset.type}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right font-medium">{asset.quantity.toLocaleString()}</td>
                  <td className="px-6 py-4 text-right">${asset.avgPrice.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right">${asset.currentPrice.toFixed(2)}</td>
                  <td className="px-6 py-4 text-right font-bold text-slate-900 dark:text-white">${totalValue.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</td>
                  <td className={`px-6 py-4 text-right font-medium ${isProfitable ? 'text-emerald-600 dark:text-emerald-400' : 'text-rose-600 dark:text-rose-400'}`}>
                    <div className="flex flex-col items-end">
                      <span>{isProfitable ? '+' : ''}{gainLoss.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
                      <span className="text-xs opacity-80 font-normal">({isProfitable ? '+' : ''}{gainLossPercent.toFixed(2)}%)</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <button 
                      onClick={() => onDelete(asset.id)}
                      className="text-slate-400 hover:text-rose-500 dark:hover:text-rose-400 transition-colors p-2 rounded-full hover:bg-rose-50 dark:hover:bg-rose-900/20 opacity-0 group-hover:opacity-100"
                      title="Delete Asset"
                    >
