import { exportPortfolioToExcel, parseExcelImport } from './services/excelService';

// Initial Mock Data
const MOCK_ASSETS: Asset[] = [
  { id: '1', symbol: 'AAPL', name: 'Apple Inc.', type: AssetType.STOCK, quantity: 50, avgPrice: 150, currentPrice: 175.50, currency: 'USD' },
  { id: '2', symbol: 'VOO', name: 'Vanguard S&P 500 ETF', type: AssetType.ETF, quantity: 20, avgPrice: 350, currentPrice: 410.20, currency: 'USD' },
  { id: '3', symbol: 'GLD', name: 'SPDR Gold Shares', type: AssetType.COMMODITY, quantity: 10, avgPrice: 180, currentPrice: 192.30, currency: 'USD' },
  { id: '4', symbol: 'MSFT', name: 'Microsoft Corp', type: AssetType.STOCK, quantity: 30, avgPrice: 280, currentPrice: 320.10, currency: 'USD' },
];

const App: React.FC = () => {
  const [assets, setAssets] = useState<Asset[]>(MOCK_ASSETS);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [aiResult, setAiResult] = useState<AIAnalysisResult | null>(null);
