                    <ReferenceLine key={i} y={y} stroke="#ef4444" strokeDasharray="3 3" label={{ position: 'right', value: `$${y.toFixed(2)}`, fill: '#ef4444', fontSize: 10 }} />
                  ))}

                  {/* Zoom Brush */}
                  {!showRSI && <Brush dataKey="date" height={30} stroke="#3b82f6" fill={darkMode ? '#1e293b' : '#f8fafc'} tickFormatter={() => ''} />}
                </ComposedChart>
              </ResponsiveContainer>
            </div>

            {/* RSI Chart */}
            {showRSI && (
              <div className="h-[30%] w-full mt-2">
                <ResponsiveContainer width="100%" height="100%">
                  <ComposedChart data={analysisData} margin={{ top: 5, right: 30, left: 0, bottom: 0 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke={darkMode ? '#1e293b' : '#f1f5f9'} vertical={false} />
                    <XAxis dataKey="date" hide />
                    <YAxis domain={[0, 100]} tick={{fontSize: 10, fill: darkMode ? '#94a3b8' : '#64748b'}} axisLine={false} tickLine={false} ticks={[30, 70]} />
                    <RechartsTooltip 
                       contentStyle={{ 
                        borderRadius: '8px', 
                        border: 'none',
                        backgroundColor: darkMode ? '#0f172a' : '#fff',
                        fontSize: '12px'
                      }}
                    />
                    <ReferenceLine y={70} stroke="#ef4444" strokeDasharray="3 3" />
                    <ReferenceLine y={30} stroke="#10b981" strokeDasharray="3 3" />
                    <Line type="monotone" dataKey="rsi" stroke="#8b5cf6" strokeWidth={1.5} dot={false} name="RSI (14)" />
                    <Brush dataKey="date" height={20} stroke="#8b5cf6" fill={darkMode ? '#1e293b' : '#f8fafc'} tickFormatter={() => ''} />
                  </ComposedChart>
                </ResponsiveContainer>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

