import { GoogleGenAI, Type } from "@google/genai";
import { Asset, AIAnalysisResult, AIAssetAnalysisResult } from "../types";

const API_KEY = process.env.API_KEY || '';

export const analyzePortfolio = async (assets: Asset[]): Promise<AIAnalysisResult> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Simplify the asset list for the prompt to save tokens
  const portfolioSummary = assets.map(a => ({
    symbol: a.symbol,
    type: a.type,
    value: (a.quantity * a.currentPrice).toFixed(2),
    allocation: ((a.quantity * a.currentPrice) / assets.reduce((sum, item) => sum + (item.quantity * item.currentPrice), 0) * 100).toFixed(1) + '%'
  }));

  const prompt = `
    Analyze the following investment portfolio summary. 
    Provide a risk score (1-10, where 10 is high risk), a brief risk assessment, 3 specific suggestions for improvement, and a comment on diversification.

    Portfolio Data:
    ${JSON.stringify(portfolioSummary, null, 2)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            riskScore: { type: Type.NUMBER, description: "Risk score from 1 to 10" },
            riskAssessment: { type: Type.STRING, description: "Short assessment of the risk level" },
            suggestions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "List of 3 actionable suggestions"
            },
            diversificationStatus: { type: Type.STRING, description: "Comment on how diversified the portfolio is" }
          },
          required: ["riskScore", "riskAssessment", "suggestions", "diversificationStatus"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIAnalysisResult;

  } catch (error) {
    console.error("Error analyzing portfolio:", error);
    // Return a fallback in case of error to prevent UI crash
    return {
      riskScore: 0,
      riskAssessment: "Could not analyze portfolio at this time.",
      suggestions: ["Ensure API Key is valid", "Check internet connection", "Try again later"],
      diversificationStatus: "Unknown"
    };
  }
};

