  const isProfitable = totalReturn >= 0;

  // Chart Data
  const chartData = useMemo(() => {
    let data = generateHistory(asset.currentPrice, timeRange);
    data = calculateSMA(data, 50); // 50 day SMA for detail view
    return data;
