    const seed = asset.symbol.length + asset.currentPrice;
    return {
      marketCap: (seed * 1000000000).toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }),
      peRatio: (15 + (seed % 20)).toFixed(2),
