import { GoogleGenAI, Type } from "@google/genai";
import { Asset, AIAnalysisResult, AIAssetAnalysisResult, RealTimeAssetData } from "../types";

const API_KEY = process.env.API_KEY || '';

export const analyzePortfolio = async (assets: Asset[]): Promise<AIAnalysisResult> => {
  if (!API_KEY) {
    throw new Error("API Key is missing. Please check your environment configuration.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Simplify the asset list for the prompt to save tokens
  const portfolioSummary = assets.map(a => ({
    symbol: a.symbol,
    type: a.type,
    value: (a.quantity * a.currentPrice).toFixed(2),
    allocation: ((a.quantity * a.currentPrice) / assets.reduce((sum, item) => sum + (item.quantity * item.currentPrice), 0) * 100).toFixed(1) + '%'
  }));

  const prompt = `
    Analyze the following investment portfolio summary. 
    Provide a risk score (1-10, where 10 is high risk), a brief risk assessment, 3 specific suggestions for improvement, and a comment on diversification.

    Portfolio Data:
    ${JSON.stringify(portfolioSummary, null, 2)}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            riskScore: { type: Type.NUMBER, description: "Risk score from 1 to 10" },
            riskAssessment: { type: Type.STRING, description: "Short assessment of the risk level" },
            suggestions: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "List of 3 actionable suggestions"
            },
            diversificationStatus: { type: Type.STRING, description: "Comment on how diversified the portfolio is" }
          },
          required: ["riskScore", "riskAssessment", "suggestions", "diversificationStatus"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIAnalysisResult;

  } catch (error) {
    console.error("Error analyzing portfolio:", error);
    // Return a fallback in case of error to prevent UI crash
    return {
      riskScore: 0,
      riskAssessment: "Could not analyze portfolio at this time.",
      suggestions: ["Ensure API Key is valid", "Check internet connection", "Try again later"],
      diversificationStatus: "Unknown"
    };
  }
};

export const analyzeAsset = async (asset: Asset): Promise<AIAssetAnalysisResult> => {
  if (!API_KEY) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `
    Provide a detailed investment analysis for ${asset.name} (${asset.symbol}).
    Include a brief business summary, a bullish case, a bearish case, a Buy/Hold/Sell rating, and a 12-month price target estimation.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING, description: "Brief business summary" },
            bullishCase: { type: Type.STRING, description: "Key reasons to be bullish" },
            bearishCase: { type: Type.STRING, description: "Key risks or reasons to be bearish" },
            rating: { type: Type.STRING, enum: ["Buy", "Hold", "Sell"], description: "Investment rating" },
            priceTarget: { type: Type.STRING, description: "Estimated price target string (e.g. '$150 - $180')" }
          },
          required: ["summary", "bullishCase", "bearishCase", "rating", "priceTarget"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIAssetAnalysisResult;
  } catch (error) {
    console.error("Error analyzing asset:", error);
    return {
      summary: "Analysis unavailable.",
      bullishCase: "N/A",
      bearishCase: "N/A",
      rating: "Hold",
      priceTarget: "N/A"
    };
  }
};

export const getRealTimeAssetData = async (symbol: string, name: string): Promise<RealTimeAssetData> => {
  if (!API_KEY) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Use search tool to find live data
  // We prefer JustETF for ETFs, but allow others for stocks
  const searchQuery = `Current financial statistics for ${name} (${symbol}) on JustETF, Google Finance, or Yahoo Finance. 
  Get the current price, market cap, P/E ratio, dividend yield, 52 week high, 52 week low, volume, and a short description.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: searchQuery,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            price: { type: Type.NUMBER, description: "Current price" },
            currency: { type: Type.STRING, description: "Currency code (USD, EUR, etc)" },
            marketCap: { type: Type.STRING, description: "Market cap with units (e.g. 2.5T USD)" },
            peRatio: { type: Type.STRING, description: "P/E Ratio or N/A" },
            dividendYield: { type: Type.STRING, description: "Dividend Yield % or N/A" },
            high52: { type: Type.NUMBER, description: "52 Week High" },
            low52: { type: Type.NUMBER, description: "52 Week Low" },
            volume: { type: Type.STRING, description: "Volume with units" },
            description: { type: Type.STRING, description: "Short description of the asset" },
            lastUpdated: { type: Type.STRING, description: "Date of data" }
          },
          required: ["price", "description"]
        }
      }
    });

    const text = response.text;
    const json = JSON.parse(text || '{}');

    // Extract source URL from grounding metadata if available
    let sourceUrl = "";
    let sourceTitle = "";
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks && groundingChunks.length > 0) {
      // Find the first web source
      const webChunk = groundingChunks.find((c: any) => c.web);
      if (webChunk && webChunk.web) {
        sourceUrl = webChunk.web.uri;
        sourceTitle = webChunk.web.title;
      }
    }

    return {
      ...json,
      sourceUrl,
      sourceTitle
    };

  } catch (error) {
    console.error("Error fetching real-time data:", error);
    // Fallback Mock Data
    return {
      price: 0,
      currency: "USD",
      marketCap: "N/A",
      peRatio: "N/A",
      dividendYield: "N/A",
      high52: 0,
      low52: 0,
      volume: "N/A",
      description: "Could not fetch live data. Please try again later.",
      lastUpdated: new Date().toLocaleDateString()
    };
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Asset, AIAssetAnalysisResult, RealTimeAssetData } from '../types';
import { ResponsiveContainer, AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, Line, ComposedChart } from 'recharts';
import { generateHistory, calculateSMA, calculateRSI } from './Charts';
import { analyzeAsset, getRealTimeAssetData } from '../services/geminiService';

interface AssetDetailProps {
  asset: Asset;
  darkMode: boolean;
  onBack: () => void;
}

export const AssetDetail: React.FC<AssetDetailProps> = ({ asset, darkMode, onBack }) => {
  const [timeRange, setTimeRange] = useState<number>(365);
  const [aiAnalysis, setAiAnalysis] = useState<AIAssetAnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  // Real Data State
  const [realData, setRealData] = useState<RealTimeAssetData | null>(null);
  const [isLoadingRealData, setIsLoadingRealData] = useState(true);

  // Fetch real data on mount
  useEffect(() => {
    let isMounted = true;
    const fetchData = async () => {
      setIsLoadingRealData(true);
      try {
        const data = await getRealTimeAssetData(asset.symbol, asset.name);
        if (isMounted) setRealData(data);
      } catch (e) {
        console.error(e);
      } finally {
        if (isMounted) setIsLoadingRealData(false);
      }
    };
    fetchData();
    return () => { isMounted = false; };
  }, [asset.symbol, asset.name]);

  // Fallback price: use real data price if available, else asset.currentPrice
  const displayPrice = realData?.price && realData.price > 0 ? realData.price : asset.currentPrice;

  // Stats derivation using displayPrice
  const totalValue = asset.quantity * displayPrice;
  const totalCost = asset.quantity * asset.avgPrice;
  const totalReturn = totalValue - totalCost;
  const returnPercent = totalCost > 0 ? (totalReturn / totalCost) * 100 : 0;
  const isProfitable = totalReturn >= 0;

  // Chart Data - still simulated for history shape, but anchored to real price
  const chartData = useMemo(() => {
    let data = generateHistory(displayPrice, timeRange);
    data = calculateSMA(data, 50); 
    return data;
  }, [displayPrice, timeRange]);

  const handleAIAnalysis = async () => {
    setIsAnalyzing(true);
    try {
      const result = await analyzeAsset(asset);
      setAiAnalysis(result);
    } catch (error) {
      console.error(error);
    } finally {
