import { generateHistory, calculateSMA, calculateRSI } from './Charts';
import { analyzeAsset, getRealTimeAssetData } from '../services/geminiService';

interface AssetDetailProps {
  asset: Asset;
  darkMode: boolean;
  onBack: () => void;
}

