            </div>
          </div>

          {/* About Section */}
          <div className="bg-white dark:bg-slate-900/50 rounded-2xl shadow-sm border border-slate-200 dark:border-white/5 p-6 transition-colors relative overflow-hidden">
             {isLoadingRealData && (
               <div className="absolute inset-0 bg-white/50 dark:bg-slate-900/50 z-10 flex items-center justify-center backdrop-blur-sm">
                 <div className="flex flex-col items-center">
                    <svg className="animate-spin h-8 w-8 text-blue-500 mb-2" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    <span className="text-xs font-bold text-slate-500">Fetching live data...</span>
                 </div>
               </div>
             )}
            <div className="flex justify-between items-start mb-4">
               <h3 className="text-slate-800 dark:text-white font-bold text-lg">About {asset.name}</h3>
               {realData && (
                 <span className="bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 text-[10px] px-2 py-1 rounded-full font-bold uppercase tracking-wide">
                   Live Data
                 </span>
               )}
            </div>
            <p className="text-slate-600 dark:text-slate-300 leading-relaxed mb-6">
              {realData?.description || `${asset.name} (${asset.symbol}) is a leading entity in the ${asset.type} sector.`}
            </p>

            <div className="grid grid-cols-2 md:grid-cols-3 gap-6 pt-4 border-t border-slate-100 dark:border-slate-800/50">
               <div>
                 <p className="text-xs text-slate-500 uppercase font-bold mb-1">Market Cap</p>
                 <p className="text-slate-900 dark:text-white font-semibold">{realData?.marketCap || '---'}</p>
               </div>
               <div>
                 <p className="text-xs text-slate-500 uppercase font-bold mb-1">P/E Ratio</p>
                 <p className="text-slate-900 dark:text-white font-semibold">{realData?.peRatio || '---'}</p>
               </div>
               <div>
                 <p className="text-xs text-slate-500 uppercase font-bold mb-1">Div Yield</p>
                 <p className="text-slate-900 dark:text-white font-semibold">{realData?.dividendYield || '---'}</p>
               </div>
               <div>
                 <p className="text-xs text-slate-500 uppercase font-bold mb-1">52W High</p>
                 <p className="text-slate-900 dark:text-white font-semibold">{realData?.high52 ? `$${realData.high52}` : '---'}</p>
               </div>
               <div>
                 <p className="text-xs text-slate-500 uppercase font-bold mb-1">52W Low</p>
                 <p className="text-slate-900 dark:text-white font-semibold">{realData?.low52 ? `$${realData.low52}` : '---'}</p>
               </div>
               <div>
                 <p className="text-xs text-slate-500 uppercase font-bold mb-1">Volume</p>
                 <p className="text-slate-900 dark:text-white font-semibold">{realData?.volume || '---'}</p>
               </div>
            </div>
          </div>
        </div>

        {/* Right Column: Holdings Stats & AI */}
        <div className="space-y-8">
           {/* Your Position Card */}
           <div className="bg-white dark:bg-slate-900/50 rounded-2xl shadow-sm border border-slate-200 dark:border-white/5 p-6 transition-colors">
             <h3 className="text-slate-800 dark:text-white font-bold text-sm uppercase tracking-wider mb-6">Your Position</h3>
             <div className="space-y-4">
                <div className="flex justify-between items-center py-2 border-b border-slate-100 dark:border-slate-800/50">
                  <span className="text-slate-500 dark:text-slate-400">Shares Owned</span>
                  <span className="font-bold text-slate-900 dark:text-white">{asset.quantity}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b border-slate-100 dark:border-slate-800/50">
                  <span className="text-slate-500 dark:text-slate-400">Avg Cost</span>
                  <span className="font-bold text-slate-900 dark:text-white">${asset.avgPrice.toFixed(2)}</span>
                </div>
                <div className="flex justify-between items-center py-2 border-b border-slate-100 dark:border-slate-800/50">
                  <span className="text-slate-500 dark:text-slate-400">Total Value</span>
                  <span className="font-bold text-slate-900 dark:text-white">${totalValue.toLocaleString(undefined, {minimumFractionDigits: 2})}</span>
                </div>
                <div className="flex justify-between items-center py-2">
                  <span className="text-slate-500 dark:text-slate-400">Total Return</span>
                  <span className={`font-bold ${isProfitable ? 'text-emerald-500' : 'text-rose-500'}`}>
                    {isProfitable ? '+' : ''}{totalReturn.toLocaleString(undefined, {minimumFractionDigits: 2})}
                  </span>
                </div>
             </div>
             <div className="grid grid-cols-2 gap-3 mt-6">
               <button className="py-3 bg-emerald-500 hover:bg-emerald-600 text-white font-bold rounded-xl transition-colors shadow-lg shadow-emerald-500/20">Buy</button>
               <button className="py-3 bg-rose-500 hover:bg-rose-600 text-white font-bold rounded-xl transition-colors shadow-lg shadow-rose-500/20">Sell</button>
             </div>
           </div>

           {/* AI Analysis Card */}
           <div className="bg-gradient-to-br from-indigo-50 to-violet-50 dark:from-indigo-900/20 dark:to-violet-900/10 rounded-2xl shadow-sm border border-indigo-100 dark:border-indigo-500/30 p-6 transition-colors relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-5">
                 <svg className="w-40 h-40 text-indigo-600 dark:text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 17h-2v-2h2v2zm2.07-7.75l-.9.92C13.45 12.9 13 13.5 13 15h-2v-.5c0-1.1.45-2.1 1.17-2.83l1.24-1.26c.37-.36.59-.86.59-1.41 0-1.1-.9-2-2-2s-2 .9-2 2H8c0-2.21 1.79-4 4-4s4 1.79 4 4c0 .88-.36 1.68-.93 2.25z"/></svg>
              </div>
              <div className="relative z-10">
                <h3 className="text-indigo-900 dark:text-indigo-100 font-bold text-lg mb-4 flex items-center gap-2">
                  <span className="w-1.5 h-6 bg-indigo-500 rounded-full"></span>
                  AI Insight
                </h3>

                {!aiAnalysis ? (
                  <div className="text-center py-6">
                    <p className="text-slate-600 dark:text-slate-300 mb-6 text-sm">Get real-time AI-powered analysis for {asset.symbol}, including price targets and investment rating.</p>
                    <button 
                      onClick={handleAIAnalysis}
                      disabled={isAnalyzing}
                      className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl transition-all shadow-lg shadow-indigo-500/20 flex items-center justify-center gap-2"
                    >
                      {isAnalyzing ? (
                         <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                           <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                           <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                         </svg>
                      ) : (
                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                      )}
                      Generate Analysis
                    </button>
                  </div>
                ) : (
                  <div className="space-y-4 animate-fade-in-down">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase">Rating</span>
                      <span className={`px-3 py-1 rounded-full text-sm font-bold ${aiAnalysis.rating === 'Buy' ? 'bg-emerald-100 text-emerald-700' : aiAnalysis.rating === 'Sell' ? 'bg-rose-100 text-rose-700' : 'bg-amber-100 text-amber-700'}`}>
                        {aiAnalysis.rating}
                      </span>
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase mb-1">Target Price</p>
                      <p className="text-xl font-bold text-slate-900 dark:text-white">{aiAnalysis.priceTarget}</p>
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase mb-1">Summary</p>
                      <p className="text-sm text-slate-700 dark:text-slate-200 leading-relaxed">{aiAnalysis.summary}</p>
                    </div>
                    <div className="pt-2 border-t border-indigo-100 dark:border-indigo-500/20">
                      <p className="text-xs font-bold text-emerald-600 mb-1">Bull Case</p>
                      <p className="text-xs text-slate-600 dark:text-slate-300">{aiAnalysis.bullishCase}</p>
                    </div>
                    <div>
                       <p className="text-xs font-bold text-rose-600 mb-1">Bear Case</p>
                       <p className="text-xs text-slate-600 dark:text-slate-300">{aiAnalysis.bearishCase}</p>
                    </div>
                  </div>
                )}
           </div>
        </div>
      </div>
    </div>
  );
};
